3042 bool InstCombinerImpl::SimplifyDemandedFPClass(Instruction *I, unsigned OpNo,
3043                                                FPClassTest DemandedMask,
3044                                                KnownFPClass &Known,
3045                                                unsigned Depth) {
3046   Use &U = I->getOperandUse(OpNo);
3047   Value *V = U.get();
3048   Type *VTy = V->getType();
3049 
3050   if (DemandedMask == fcNone) {
3051     if (isa<UndefValue>(V))
3052       return false;
3053     replaceUse(U, PoisonValue::get(VTy));
3054     return true;
3055   }
3056 
3057   // Handle constant
3058   Instruction *VInst = dyn_cast<Instruction>(V);
3059   if (!VInst) {
3060     // Handle constants and arguments
3061     Known = computeKnownFPClass(V, fcAllFlags, I, Depth);
3062 
3063     FPClassTest ValidResults = DemandedMask & Known.KnownFPClasses;
3064     if (ValidResults == fcNone) {
3065       if (isa<UndefValue>(V))
3066         return false;
3067       replaceUse(U, PoisonValue::get(VTy));
3068       return true;
3069     }
3070 
3071     // Do not try to replace values which are already constants (unless we are
3072     // folding to poison). Doing so could promote poison elements to non-poison
3073     // constants.
3074     if (isa<Constant>(V))
3075       return false;
3076 
3077     Value *FoldedToConst = getFPClassConstant(VTy, ValidResults);
3078     if (!FoldedToConst || FoldedToConst == V)
3079       return false;
3080 
3081     replaceUse(U, FoldedToConst);
3082     return true;
3083   }
3084 
3085   if (Depth == MaxAnalysisRecursionDepth)
3086     return false;
3087 
3088   Value *NewVal;
3089 
3090   if (VInst->hasOneUse()) {
3091     // If the instruction has one use, we can directly simplify it.
3092     NewVal = SimplifyDemandedUseFPClass(VInst, DemandedMask, Known, I, Depth);
3093   } else {
3094     // If there are multiple uses of this instruction, then we can simplify
3095     // VInst to some other value, but not modify the instruction.
3096     NewVal = SimplifyMultipleUseDemandedFPClass(VInst, DemandedMask, Known, I,
3097                                                 Depth);
3098   }
3099 
3100   if (!NewVal)
3101     return false;
3102   if (Instruction *OpInst = dyn_cast<Instruction>(U))
3103     salvageDebugInfo(*OpInst);
3104 
3105   replaceUse(U, NewVal);
3106   return true;
3107 }
